// 10 small delete calls that all belong to the SAME session -- the agent
// 'fragments' one 50-row delete into ten 5-row calls, trying to stay under
// any single-call threshold. The session id is generated ONCE here (unique
// per workflow import/execution via $execution.id + a random suffix, so a
// shared api-dev endpoint used by many people running this demo does not
// pollute a single global session), then baked identically into all 10
// items so every /v1/decide call below shares it.
//
// Axes are deliberately chosen so R2 (irreversible+broad+production) does
// NOT fire on any single call -- this demo isolates R5, the session delete
// budget (reeflex-core/policy/reeflex.rego, delete_session_budget = 20).
const sessionId = `frag-demo-${$execution.id}-${Math.floor(Math.random() * 1e9)}`;
const items = [];
for (let i = 1; i <= 10; i++) {
  items.push({
    json: {
      i,
      sessionId,
      table: 'audit_logs',
      count: 5,
      reversibility: 'recoverable',
      blastRadius: 'single',
      environment: 'production',
      externality: 'internal'
    }
  });
}
return items;
